(async () => {
    try {
        const currentFile = app.workspace.getActiveFile();
        if (!currentFile) {
            new Notice("No active file found");
            return;
        }

        const fileContent = await app.vault.read(currentFile);

        // Strategy: Find the loot callout that contains the button reference
        // by looking for the callout immediately before the button in the file

        // Find all loot callouts with their positions
        const lootCalloutRegex = /(%%\s*loot-id:\s*([^%\s]+)\s*%%\s*\n)((?:>\s*)*)\[!loot\][^\n]*\n((?:(?:>\s*.*\n)*?))/gm;
        const callouts = [];
        let calloutMatch;

        while ((calloutMatch = lootCalloutRegex.exec(fileContent)) !== null) {
            const calloutId = calloutMatch[2];
            const calloutPrefix = calloutMatch[3];
            const calloutContent = calloutMatch[4];
            const calloutStart = calloutMatch.index;
            const calloutEnd = calloutMatch.index + calloutMatch[0].length;

            // Look for the button reference after this callout
            const afterCallout = fileContent.substring(calloutEnd, calloutEnd + 300);
            const buttonRegex = />\s*`BUTTON\[add-to-session-loot[^\]]*\]`/;

            if (buttonRegex.test(afterCallout)) {
                callouts.push({
                    id: calloutId,
                    prefix: calloutPrefix,
                    content: calloutContent,
                    start: calloutStart,
                    end: calloutEnd
                });
            }
        }

        if (callouts.length === 0) {
            new Notice("No loot callouts with buttons found");
            return;
        }

        // For simplicity, if multiple callouts are found, we'll process the first one
        // In practice, only one should match due to the button proximity check
        const targetCallout = callouts[0];

        console.log("Processing callout with ID:", targetCallout.id);

        // Extract bullet points from the target callout
        const bulletRegex = />\s*-\s*(.+)/g;
        const bullets = [];
        let bulletMatch;

        while ((bulletMatch = bulletRegex.exec(targetCallout.content)) !== null) {
            if (bulletMatch[1].trim()) {
                bullets.push("- " + bulletMatch[1].trim());
            }
        }

        console.log("Extracted bullets:", bullets);

        if (bullets.length === 0) {
            new Notice("No loot items found to add");
            return;
        }

        // Find the Session Loot section
        const sessionLootRegex = /((?:>\s*)*)####\s*💎Loot\n((?:(?!(?:>\s*)*####).*\n)*)/;
        const sessionLootMatch = fileContent.match(sessionLootRegex);

        if (!sessionLootMatch) {
            new Notice("Could not find '#### 💎Loot' section");
            return;
        }

        const sessionLootCalloutPrefix = sessionLootMatch[1];
        const beforeLootSection = fileContent.substring(0, sessionLootMatch.index + sessionLootMatch[0].length - sessionLootMatch[2].length);
        const currentLootContent = sessionLootMatch[2];
        const afterLootSection = fileContent.substring(sessionLootMatch.index + sessionLootMatch[0].length);

        // Prepare new loot content
        let newLootContent = currentLootContent;

        if (currentLootContent.trim()) {
            if (!newLootContent.endsWith("\n")) {
                newLootContent += "\n";
            }
        }

        // Add the prefixed bullets
        const prefixedBullets = bullets.map(bullet => sessionLootCalloutPrefix + bullet);
        newLootContent += prefixedBullets.join("\n") + "\n";

        // Reconstruct and save
        const newFileContent = beforeLootSection + newLootContent + afterLootSection;
        await app.vault.modify(currentFile, newFileContent);

        new Notice(`Added ${bullets.length} loot item(s) to Session Loot`);

    } catch (error) {
        console.error("Error adding to session loot:", error);
        new Notice("Error: " + error.message);
    }
})();
